package main

import (
    "fmt"
    "sync"
)

type Account struct {
    Balance float64
}

var (
    balances = make(map[string]Account)
    mu       sync.RWMutex
)

func checkBalance(account string) (float64, error) {
    mu.RLock()
    balance := balances[account].Balance
    mu.RUnlock()

    return balance, nil
}

func updateBalance(account string, amount float64) error {
    mu.Lock()
    defer mu.Unlock()

    if amount < 0 {
        return fmt.Errorf("invalid amount")
    }

    balances[account].Balance += amount

    return nil
}

func deposit(account string, amount float64) {
    _, err := updateBalance(account, amount)
    if err != nil {
        panic(err)
    }
}

func withdraw(account string, amount float64) {
    _, err := updateBalance(account, -amount)
    if err != nil {
        panic(err)
    }
}

func processTransaction(account string, amount float64, op func(string, float64)) {
    balance, _ := checkBalance(account)
    if amount > balance {
        fmt.Printf("Insufficient funds for account %s\n", account)
        return
    }

    op(account, amount)
}

func main() {
    go deposit("1", 100.0)
    go withdraw("2", 50.0)

    // wait for transactions to complete
    select {}
}